if('serviceWorker'in navigator){const initSw=async()=>{try{const registration=await navigator.serviceWorker.register('/sw-idb.js',{scope:'/',updateViaCache:'none'});console.log('[APP] SW registered:',registration.scope);registration.addEventListener('updatefound',()=>{const newWorker=registration.installing;if(!newWorker){return}newWorker.addEventListener('statechange',()=>{if(newWorker.state==='installed'&&navigator.serviceWorker.controller){console.log('[APP] New SW version installed; activation pending.')}})});setInterval(()=>{registration.update().catch((err)=>{console.warn('[APP] Periodic update check failed:',err)})},60*60*1000)}catch(err){console.error('[APP] SW registration failed:',err)}};let refreshing=false;navigator.serviceWorker.addEventListener('controllerchange',()=>{if(refreshing){return;}refreshing=true;window.location.reload()});navigator.serviceWorker.addEventListener('message',(event)=>{const{type,data}=event.data??{};switch(type){case 'SYNC_STATUS':console.log('[APP] Pending sync requests:',data?.pendingCount??0);break;case 'PRECACHE_METADATA':console.log('[APP] Precache metadata:',data);break;case 'BG_SYNC_COMPLETE':console.log('[APP] Background sync complete.');break}});if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initSw)}else{initSw()}function queryPendingRetries(){const sw=navigator.serviceWorker.controller;if(!sw){console.warn('[APP] No active controller to query.');return}sw.postMessage({type:'QUERY_SYNC_STATUS'})}function requestManualRetry(){const sw=navigator.serviceWorker.controller;if(!sw){return}sw.postMessage({type:'TRIGGER_RETRY'})}}
